import java.util.ArrayList;

public class TSTNode {
    char data;
    TSTNode left, middle, right;
    ArrayList<String> al;
    boolean is_End_Of_String;

    public TSTNode(char data) {
        this.data = data;
        this.left = null;
        this.middle = null;
        this.right = null;
        this.al = new ArrayList<>();
        this.is_End_Of_String = false;
    }

    // Traverse the tree and print stored words (if any)
    public void traverse() {
        if (left != null) left.traverse();
        if (is_End_Of_String && al != null) {
            for (String s : al) {
                System.out.println(s);
            }
        }
        if (middle != null) middle.traverse();
        if (right != null) right.traverse();
    }

    // Clear the tree/node data
    public void makeEmpty() {
        left = middle = right = null;
        if (al != null) al.clear();
        is_End_Of_String = false;
    }

    // Check if the node (and its subtree) is empty
    public boolean isEmpty() {
        return left == null && middle == null && right == null
                && (al == null || al.isEmpty())
                && !is_End_Of_String;
    }

    // Public insert: adds a word to the TST; returns the (possibly new) root
    public TSTNode insert(String word) {
        if (word == null || word.isEmpty()) return this;
        return insert(this, word, 0);
    }

    // Recursive insertion helper
    private TSTNode insert(TSTNode node, String word, int index) {
        char c = word.charAt(index);
        if (node == null) node = new TSTNode(c);

        if (c < node.data) {
            node.left = insert(node.left, word, index);
        } else if (c > node.data) {
            node.right = insert(node.right, word, index);
        } else {
            if (index + 1 == word.length()) {
                node.is_End_Of_String = true;
                if (node.al == null) node.al = new ArrayList<>();
                node.al.add(word);
            } else {
                node.middle = insert(node.middle, word, index + 1);
            }
        }
        return node;
    }

    // String representation: collect and print stored words
    public String toString() {
        StringBuilder out = new StringBuilder();
        collect(this, new StringBuilder(), out);
        return out.toString();
    }

    private void collect(TSTNode node, StringBuilder prefix, StringBuilder out) {
        if (node == null) return;
        collect(node.left, new StringBuilder(prefix.toString()), out);
        StringBuilder newPrefix = new StringBuilder(prefix);
        newPrefix.append(node.data);
        if (node.is_End_Of_String) {
            if (node.al != null) {
                for (String s : node.al) {
                    out.append(newPrefix.toString()).append(" -> ").append(s).append("\n");
                }
            }
        }
        collect(node.middle, newPrefix, out);
        collect(node.right, new StringBuilder(prefix.toString()), out);
    }

    // Demonstration main method
    public static void main(String[] args) {
        // Simple usage example
        TSTNode root = new TSTNode('\0');
        // Insert some example words
        root = root.insert("cat");
        root = root.insert("cap");
        root = root.insert("dog");
        // Print stored words (as a demonstration of traversal/output)
        System.out.print(root.toString());
    }

    // Delete a specific word (placeholder for actual deletion logic)
    public void delete(String word) {
        // Deletion logic would go here (path-based removal in a TST)
    }

    // Delete all words / reset the structure
    public void delete() {
        makeEmpty();
    }
}
